      name: "Garlic Bread",
      description: "Classic garlic bread, with a hint of herbs.",
      price: 5,
    },
    {
      id: 2,
      category: "Appetizers",
      name: "Soup of the Day",
      description: "A delicious way to start your meal.",
      price: 7,
