    {
      id: 3,
      category: "Main Courses",
      name: "Grilled Salmon",
      description: "Fresh salmon that's grilled to perfection.",
      price: 15,
    },
    {
      id: 4,
      category: "Main Courses",
      name: "Steak",
      description: "High-quality beef with our special sauce.",
      price: 18,
    },
    {
      id: 5,
