    {
      id: 8,
      category: "Appetizers",
      name: "Chicken Wings",
      description: "Spicy wings with a side of ranch dressing.",
      price: 10,
    },
    {
      id: 9,
      category: "Main Courses",
      name: "Pasta Carbonara",
      description: "Creamy pasta with pancetta and parmesan.",
      price: 12,
