    {
      id: 11,
      category: "Drinks",
      name: "Cola",
      description: "Refreshing cola beverage.",
      price: 3,
    },
    {
      id: 12,
      category: "Drinks",
      name: "Orange Juice",
      description: "Freshly squeezed orange juice.",
      price: 4,
    },
    {
      id: 13,
      category: "Drinks",
      name: "Coffee",
      description: "Hot and strong coffee.",
      price: 2,
    },
    {
      id: 14,
      category: "Desserts",
      name: "Lemon Tart",
      description: "Tart and sweet lemon filling with a buttery crust.",
      price: 6,
    },
    {
      id: 15,
      category: "Main Courses",
      name: "Shrimp Scampi",
      description: "Shrimp sautéed in garlic butter and white wine.",
      price: 16,
