    {
      id: 17,
      category: "Main Courses",
      name: "Fettuccine Alfredo",
      description: "Rich and creamy fettuccine pasta.",
      price: 13,
    },
    {
      id: 18,
      category: "Appetizers",
      name: "Spring Rolls",
      description: "Crispy rolls filled with fresh vegetables.",
      price: 7,
    },
    {
      id: 19,
      category: "Desserts",
      name: "Pancakes",
      description: "Fluffy pancakes served with maple syrup and butter.",
      price: 8,
    },
    {
      id: 20,
      category: "Drinks",
      name: "Milkshake",
      description: "Creamy milkshake with various flavors.",
      price: 5,
    },
  ];

  return (
    <div className="App">
      <Menu menuItemsData={menuItems} />
    </div>
  );
}

export default App;
